// @vitest-environment node
/**
 * SPEC-036: cola persistente de preguntas del asistente (main) — encolado de
 * candidatas aceptadas, persistencia anti-descarte (la más reciente primero),
 * cola en el mensaje de usuario con systemBlocks byte-idénticos (SPEC-023
 * intacta), supresión determinista por similitud, gate de capacidad (>=),
 * resolución automática por índices del snapshot, anclado/desanclado
 * (setAssistantPinned) y tamaño de cola configurable (assistantSettings).
 * Generated by QA Dev agent.
 *
 * Arnés de SPEC-016/021 (SDK y Deepgram mockeados con clases de error espejo,
 * store/repository y transcriptionService REALES, fake timers solo de Date).
 */
import { mkdtempSync, writeFileSync } from 'fs'
import { tmpdir } from 'os'
import { join } from 'path'
import type { WebContents } from 'electron'
import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest'
import {
  FALLBACK_INTERVAL_MS,
  MIN_INTERVAL_MS,
  MIN_NEW_FINAL_LINES,
  normalizeQuestion,
  setAssistantPinned,
  startAssistant,
  stopAssistant
} from '../../../src/main/assistantService'
import * as repository from '../../../src/main/db/repository'
import { initStore } from '../../../src/main/db/store'
import type { DeepgramCallbacks } from '../../../src/main/deepgramService'
import { resetTranscription, startTranscription } from '../../../src/main/transcriptionService'
import type {
  AssistantQueue,
  AssistantUpdateEvent
} from '../../../src/renderer/src/types/assistant'

const harness = vi.hoisted(() => {
  /** Jerarquía espejo de la del SDK: instanceof debe funcionar en mapSdkError. */
  class APIError extends Error {}
  class AuthenticationError extends APIError {}
  class RateLimitError extends APIError {}
  class APIConnectionError extends APIError {}
  return {
    create: vi.fn(),
    dgInstances: [] as unknown[],
    errors: { APIError, AuthenticationError, RateLimitError, APIConnectionError }
  }
})

vi.mock('@anthropic-ai/sdk', () => {
  class MockAnthropic {
    static APIError = harness.errors.APIError
    static AuthenticationError = harness.errors.AuthenticationError
    static RateLimitError = harness.errors.RateLimitError
    static APIConnectionError = harness.errors.APIConnectionError
    readonly messages = { create: harness.create }
  }
  return { default: MockAnthropic }
})

vi.mock('../../../src/main/deepgramService', () => ({
  DeepgramConnection: class {
    apiKey: string
    callbacks: DeepgramCallbacks
    opened = false
    isOpen = false
    sendAudio = vi.fn(() => true)
    sendKeepAlive = vi.fn()
    closeStream = vi.fn()
    terminate = vi.fn()

    constructor(apiKey: string, callbacks: DeepgramCallbacks) {
      this.apiKey = apiKey
      this.callbacks = callbacks
      harness.dgInstances.push(this)
    }
  },
  classifyConnectionFailure: vi.fn(() => Promise.resolve('other' as const))
}))

vi.mock('electron', () => ({
  app: {
    getPath: (): string => {
      throw new Error('app.getPath no debe usarse en tests: initStore recibe baseDir inyectado')
    }
  },
  safeStorage: {
    isEncryptionAvailable: (): boolean => true,
    encryptString: (plain: string): Buffer => Buffer.from(plain, 'utf8'),
    decryptString: (blob: Buffer): string => blob.toString('utf8')
  }
}))

interface FakeConnection {
  callbacks: DeepgramCallbacks
  opened: boolean
  isOpen: boolean
}

/** Parámetros relevantes de una llamada create del asistente. */
interface CreateParams {
  system: unknown
  messages: Array<{ role: string; content: string }>
  output_config: {
    format: {
      type: string
      schema: {
        properties: Record<string, unknown>
        required: string[]
      }
    }
  }
}

function createCall(index: number): CreateParams {
  return harness.create.mock.calls[index][0] as CreateParams
}

/** Respuesta del SDK con bloque thinking + bloque text (el JSON va en text). */
function sdkResponse(payload: Record<string, unknown>): unknown {
  return {
    stop_reason: 'end_turn',
    content: [
      { type: 'thinking', thinking: 'razonamiento' },
      { type: 'text', text: JSON.stringify(payload) }
    ]
  }
}

/** Payload con el contrato de salida de SPEC-036 (resolvedQueueIndexes). */
function analysisPayload(overrides: Record<string, unknown> = {}): Record<string, unknown> {
  return {
    action: 'continue',
    suggestedQuestion: '¿Cuándo fue la última vez que pasó?',
    reason: 'Ya hay material concreto para avanzar',
    alarms: [],
    objectivesMet: [],
    resolvedQueueIndexes: [],
    ...overrides
  }
}

function createSender(): { sender: WebContents; send: ReturnType<typeof vi.fn> } {
  const send = vi.fn()
  const senderLike = {
    isDestroyed: (): boolean => false,
    send
  }
  return { sender: senderLike as unknown as WebContents, send }
}

function assistantEvents(send: ReturnType<typeof vi.fn>): AssistantUpdateEvent[] {
  return send.mock.calls
    .filter((call) => call[0] === 'assistant:update')
    .map((call) => call[1] as AssistantUpdateEvent)
}

const BASE_TIME_MS = 1_000_000_000

let send: ReturnType<typeof vi.fn>
let connection: FakeConnection
let baseDir = ''
let lineCounter = 0
let analysisCount = 0

/** Inyecta una línea final por la vía pública (transcripción real mockeada). */
function feedFinal(): void {
  lineCounter += 1
  connection.callbacks.onResult({
    channelIndex: lineCounter % 2,
    transcript: `Línea de conversación ${lineCounter}`,
    isFinal: true,
    startSeconds: lineCounter,
    durationSeconds: 1,
    speaker: 0
  })
}

/** Último estado de la cola emitido por main (fuente de verdad del renderer). */
function lastQueue(): AssistantQueue {
  const queue = assistantEvents(send).at(-1)?.queue
  if (queue === undefined) {
    throw new Error('sin eventos del asistente todavía')
  }
  return queue
}

function pendingQuestions(): string[] {
  return lastQueue().pending.map((item) => item.suggestedQuestion)
}

/**
 * Arranca transcripción + asistente sobre una entrevista con objetivos y
 * guión. `queueSize` persiste el ajuste ANTES de startAssistant (AC del
 * tamaño configurable); sin él, la sesión usa el default 3.
 */
function startSession(options: { queueSize?: number } = {}): void {
  if (options.queueSize !== undefined) {
    repository.setAssistantSettings({ queueSize: options.queueSize })
  }
  const discovery = repository.createDiscovery({ name: 'Discovery Maurya' })
  const interview = repository.createInterview({
    discoveryId: discovery.id,
    title: 'Entrevista con cola'
  })
  repository.updateInterview(interview.id, {
    objectives: ['Objetivo cero', 'Objetivo uno'],
    scriptMarkdown: '# Guión de la entrevista'
  })

  const transcriptionSender = createSender()
  startTranscription(transcriptionSender.sender)
  connection = harness.dgInstances[0] as FakeConnection
  connection.opened = true
  connection.isOpen = true
  connection.callbacks.onOpen()

  const assistantSender = createSender()
  send = assistantSender.send
  startAssistant(assistantSender.sender, interview.id)
}

/**
 * Ejecuta UN análisis completo: avanza la ventana de 20 s si no es el
 * primero, inyecta 3 líneas finales y espera analyzing→active (cada análisis
 * exitoso añade exactamente 2 eventos, con o sin candidata aceptada).
 */
async function analyze(overrides: Record<string, unknown> = {}): Promise<void> {
  analysisCount += 1
  const expectedCalls = analysisCount
  const eventsBefore = assistantEvents(send).length
  harness.create.mockResolvedValueOnce(sdkResponse(analysisPayload(overrides)))
  if (expectedCalls > 1) {
    vi.setSystemTime(BASE_TIME_MS + (expectedCalls - 1) * (MIN_INTERVAL_MS + 1000))
  }
  feedFinal()
  feedFinal()
  feedFinal()
  await vi.waitFor(() => expect(harness.create).toHaveBeenCalledTimes(expectedCalls))
  await vi.waitFor(() => {
    const events = assistantEvents(send)
    expect(events.length).toBeGreaterThanOrEqual(eventsBefore + 2)
    expect(events.at(-1)?.state).toBe('active')
  })
}

beforeEach(() => {
  vi.clearAllMocks()
  harness.dgInstances.length = 0
  lineCounter = 0
  analysisCount = 0
  vi.useFakeTimers({ toFake: ['Date'] })
  vi.setSystemTime(BASE_TIME_MS)
  baseDir = mkdtempSync(join(tmpdir(), 'maurya-assistant-queue-'))
  initStore(baseDir)
  process.env['ANTHROPIC_API_KEY'] = 'sk-ant-test'
  process.env['DEEPGRAM_API_KEY'] = 'dg-test'
})

afterEach(() => {
  stopAssistant()
  resetTranscription()
  vi.useRealTimers()
  delete process.env['ANTHROPIC_API_KEY']
  delete process.env['DEEPGRAM_API_KEY']
})

describe('assistantService (cola SPEC-036)', () => {
  describe('pending queue (anti-discard persistence)', () => {
    // SPEC-036 · AC-01 (servicio: la candidata aceptada entra con su forma completa)
    it('enqueues the accepted candidate as a queue item with action, alarms, question, reason and id', async () => {
      startSession()
      await analyze({
        action: 'dig_deeper',
        suggestedQuestion: '¿Cuándo fue la última vez que pasó?',
        reason: 'Falta un caso concreto: pide el último episodio',
        alarms: ['generic']
      })

      const queue = lastQueue()
      expect(queue.pending).toHaveLength(1)
      expect(queue.pinned).toEqual([])
      expect(queue.pending[0]).toMatchObject({
        action: 'dig_deeper',
        suggestedQuestion: '¿Cuándo fue la última vez que pasó?',
        reason: 'Falta un caso concreto: pide el último episodio',
        alarms: ['generic']
      })
      // El id lo genera main al aceptar (clave de pin/unpin)
      expect(typeof queue.pending[0].id).toBe('string')
      expect(queue.pending[0].id.length).toBeGreaterThan(0)
    })

    // SPEC-036 · AC-02 (servicio: ambas conviven, la más reciente primero)
    it('keeps the previous question when a new distinct candidate arrives, most recent first', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Cuándo fue la última vez que pasó?' })
      await analyze({ suggestedQuestion: '¿Quién más participó en esa decisión?' })

      expect(pendingQuestions()).toEqual([
        '¿Quién más participó en esa decisión?',
        '¿Cuándo fue la última vez que pasó?'
      ])
      // Las dos candidatas aceptadas cuentan en el registro de la sesión
      expect(stopAssistant()?.suggestionCount).toBe(2)
    })

    // SPEC-036 · AC-03 (la cola viaja en el MENSAJE DE USUARIO; el prefijo
    // cacheado de SPEC-023 permanece byte-idéntico entre análisis)
    it('sends the queued questions (pending and pinned) numbered in the user message keeping the system blocks byte-identical', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Cuándo fue la última vez que pasó?' })
      await analyze({ suggestedQuestion: '¿Quién más participó en esa decisión?' })
      // Ancla la más antigua: el tercer análisis debe marcarla "(anclada)"
      const pinnedId = lastQueue().pending[1].id
      setAssistantPinned(pinnedId, true)
      await analyze({ suggestedQuestion: '¿Cuánto pagasteis por la solución actual?' })

      // Primer análisis: cola vacía → "ninguna"
      expect(createCall(0).messages[0].content).toContain(
        '## Preguntas en cola (índices 0-based)\nninguna'
      )
      // Tercer análisis: pendientes primero (0..p-1) y las ancladas marcadas
      const thirdUser = createCall(2).messages[0].content
      expect(thirdUser).toContain(
        '## Preguntas en cola (índices 0-based)\n0. ¿Quién más participó en esa decisión?\n1. (anclada) ¿Cuándo fue la última vez que pasó?'
      )
      // systemBlocks byte-idénticos entre TODAS las llamadas (SPEC-023) y sin
      // rastro de la cola en el prefijo cacheado
      expect(JSON.stringify(createCall(1).system)).toBe(JSON.stringify(createCall(0).system))
      expect(JSON.stringify(createCall(2).system)).toBe(JSON.stringify(createCall(0).system))
      expect(JSON.stringify(createCall(0).system)).not.toContain('Preguntas en cola')
    })

    // SPEC-036 · AC-04 (normalización determinista de la segunda barrera)
    it('normalizes case, punctuation and whitespace when comparing questions', () => {
      const reference = normalizeQuestion('¿Cuándo fue la última vez que pasó?')
      expect(normalizeQuestion('  CUÁNDO   fue la última vez que pasó!!! ')).toBe(reference)
      expect(normalizeQuestion('cuándo, fue la última vez... que pasó')).toBe(reference)
      // Una pregunta distinta NO colisiona
      expect(normalizeQuestion('¿Quién más participó?')).not.toBe(reference)
    })

    // SPEC-036 · AC-04 (servicio: la casi-duplicada se descarta y la cola no cambia)
    it('discards a candidate that only differs in case, spacing or punctuation keeping the queue unchanged', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Cuándo fue la última vez que pasó?' })
      await analyze({ suggestedQuestion: '  cuándo fue   la última vez que pasó ' })

      expect(pendingQuestions()).toEqual(['¿Cuándo fue la última vez que pasó?'])
      // La suprimida no cuenta como sugerencia de la sesión
      expect(stopAssistant()?.suggestionCount).toBe(1)
    })

    // SPEC-036 · AC-05 + AC-18 (default 3 sin ajuste persistido: la 4ª se descarta)
    it('discards new candidates when the pending queue is at the default size of 3', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Pregunta uno?' })
      await analyze({ suggestedQuestion: '¿Pregunta dos?' })
      await analyze({ suggestedQuestion: '¿Pregunta tres?' })
      await analyze({ suggestedQuestion: '¿Pregunta cuatro?' })

      expect(pendingQuestions()).toEqual(['¿Pregunta tres?', '¿Pregunta dos?', '¿Pregunta uno?'])
      expect(stopAssistant()?.suggestionCount).toBe(3)
    })

    // SPEC-036 · AC-06 (resolución automática: sale la cubierta, entra la candidata)
    it('auto-resolves the queued question marked as covered and lets the new candidate take the freed slot', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Pregunta uno?' })
      await analyze({ suggestedQuestion: '¿Pregunta dos?' })
      await analyze({ suggestedQuestion: '¿Pregunta tres?' })

      // Cola llena [tres, dos, uno]; el análisis marca el índice 2 (uno) como
      // ya cubierto → sale y la candidata nueva ocupa el hueco
      await analyze({ suggestedQuestion: '¿Pregunta cuatro?', resolvedQueueIndexes: [2] })

      expect(pendingQuestions()).toEqual(['¿Pregunta cuatro?', '¿Pregunta tres?', '¿Pregunta dos?'])
    })

    // SPEC-036 · AC-07 (la cola es estado de sesión: una grabación nueva arranca vacía)
    it('starts every new assistant session with an empty queue', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Pregunta uno?' })
      expect(lastQueue().pending).toHaveLength(1)

      stopAssistant()
      const next = createSender()
      startAssistant(next.sender, repository.listAllInterviews()[0].id)

      const firstEvent = assistantEvents(next.send)[0]
      expect(firstEvent).toEqual({
        state: 'idle',
        queue: { pending: [], pinned: [] },
        objectivesMet: []
      })
    })
  })

  describe('manual pinning', () => {
    // SPEC-036 · AC-08 + AC-12 (anclar libera hueco: las ancladas no cuentan)
    it('pins a question out of the pending count so a new candidate still enters with the queue previously full', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Pregunta uno?' })
      await analyze({ suggestedQuestion: '¿Pregunta dos?' })
      await analyze({ suggestedQuestion: '¿Pregunta tres?' })

      const pinnedId = lastQueue().pending[2].id // la más antigua: uno
      setAssistantPinned(pinnedId, true)

      // Re-emisión inmediata con la cola mutada y estado derivado, SIN llamada
      // extra al LLM (los disparadores no cambian por la gestión de la cola)
      const afterPin = assistantEvents(send).at(-1)
      expect(afterPin?.state).toBe('active')
      expect(afterPin?.queue.pending.map((item) => item.suggestedQuestion)).toEqual([
        '¿Pregunta tres?',
        '¿Pregunta dos?'
      ])
      expect(afterPin?.queue.pinned.map((item) => item.suggestedQuestion)).toEqual([
        '¿Pregunta uno?'
      ])
      expect(harness.create).toHaveBeenCalledTimes(3)

      // Con 2 pendientes + 1 anclada, la candidata nueva SÍ entra
      await analyze({ suggestedQuestion: '¿Pregunta cuatro?' })
      expect(pendingQuestions()).toEqual(['¿Pregunta cuatro?', '¿Pregunta tres?', '¿Pregunta dos?'])
      expect(lastQueue().pinned.map((item) => item.suggestedQuestion)).toEqual(['¿Pregunta uno?'])
    })

    // SPEC-036 · AC-10 (las ancladas nunca se auto-resuelven)
    it('never auto-resolves a pinned question even when the analysis marks its index as covered', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Pregunta uno?' })
      setAssistantPinned(lastQueue().pending[0].id, true)

      // En el prompt la cola es [(anclada) uno] con índice 0: marcarla como
      // cubierta debe ignorarse (tramo anclado del snapshot)
      await analyze({ suggestedQuestion: '¿Pregunta dos?', resolvedQueueIndexes: [0] })

      expect(lastQueue().pinned.map((item) => item.suggestedQuestion)).toEqual(['¿Pregunta uno?'])
      expect(pendingQuestions()).toEqual(['¿Pregunta dos?'])
    })

    // SPEC-036 · AC-11 + decisión asumida (desanclar con cola llena: vuelve al
    // frente de pendientes por encima del máximo y bloquea candidatas nuevas)
    it('returns an unpinned question to the front of pending and blocks new candidates while over the size', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Pregunta uno?' })
      await analyze({ suggestedQuestion: '¿Pregunta dos?' })
      await analyze({ suggestedQuestion: '¿Pregunta tres?' })
      const pinnedId = lastQueue().pending[2].id // uno
      setAssistantPinned(pinnedId, true)
      await analyze({ suggestedQuestion: '¿Pregunta cuatro?' }) // pendientes llenas de nuevo

      setAssistantPinned(pinnedId, false)
      // Desanclada al FRENTE de pendientes, aunque supere el máximo (4 > 3)
      expect(pendingQuestions()).toEqual([
        '¿Pregunta uno?',
        '¿Pregunta cuatro?',
        '¿Pregunta tres?',
        '¿Pregunta dos?'
      ])
      expect(lastQueue().pinned).toEqual([])

      // Por encima del máximo NO entran candidatas nuevas (gate >=)
      await analyze({ suggestedQuestion: '¿Pregunta cinco?' })
      expect(pendingQuestions()).toEqual([
        '¿Pregunta uno?',
        '¿Pregunta cuatro?',
        '¿Pregunta tres?',
        '¿Pregunta dos?'
      ])
    })
  })

  describe('configurable queue size', () => {
    // SPEC-036 · AC-17 (una sesión nueva usa el tamaño guardado)
    it('uses the persisted queue size as the pending maximum for a new session', async () => {
      startSession({ queueSize: 1 })
      await analyze({ suggestedQuestion: '¿Pregunta uno?' })
      await analyze({ suggestedQuestion: '¿Pregunta dos?' })

      // Con tamaño 1 la segunda candidata se descarta
      expect(pendingQuestions()).toEqual(['¿Pregunta uno?'])
      expect(stopAssistant()?.suggestionCount).toBe(1)
    })

    // SPEC-036 · AC-18 (almacén ilegible → default 3, el asistente nunca se bloquea)
    it('keeps the assistant working with the default size after recovering from an unreadable store', async () => {
      // db.json ilegible: initStore recupera un almacén vacío sin crashear y
      // getAssistantSettings normaliza al default (repository.assistantSettings)
      writeFileSync(join(baseDir, 'db.json'), '{corrupto')
      initStore(baseDir)
      startSession()

      await analyze({ suggestedQuestion: '¿Pregunta uno?' })
      expect(assistantEvents(send).at(-1)?.state).toBe('active')
      expect(pendingQuestions()).toEqual(['¿Pregunta uno?'])
    })
  })

  describe('existing states and triggers (regression)', () => {
    // SPEC-036 · AC-19/AC-20 (analyzing y error transportan la cola completa)
    it('carries the full queue in analyzing and error events so the renderer never loses it', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Pregunta uno?' })

      harness.create.mockRejectedValueOnce(
        new harness.errors.APIConnectionError('sin conexión con la API')
      )
      vi.setSystemTime(BASE_TIME_MS + 10 * (MIN_INTERVAL_MS + 1000))
      feedFinal()
      feedFinal()
      feedFinal()
      await vi.waitFor(() => {
        expect(assistantEvents(send).at(-1)?.state).toBe('error')
      })

      const events = assistantEvents(send)
      const analyzing = events.filter((event) => event.state === 'analyzing').at(-1)
      const error = events.at(-1)
      expect(analyzing?.queue.pending.map((item) => item.suggestedQuestion)).toEqual([
        '¿Pregunta uno?'
      ])
      expect(error?.queue.pending.map((item) => item.suggestedQuestion)).toEqual(['¿Pregunta uno?'])
    })

    // SPEC-036 · AC-23 (disparadores SPEC-016/023 intactos: 3 líneas / 20 s / 45 s)
    it('keeps the SPEC-016/023 triggers untouched by the queue management', () => {
      expect(MIN_NEW_FINAL_LINES).toBe(3)
      expect(MIN_INTERVAL_MS).toBe(20000)
      expect(FALLBACK_INTERVAL_MS).toBe(45000)
    })

    // SPEC-036 · contrato de salida (resolvedQueueIndexes requerido en el schema)
    it('declares resolvedQueueIndexes as a required integer array in the structured output schema', async () => {
      startSession()
      await analyze()

      const schema = createCall(0).output_config.format.schema
      expect(schema.properties.resolvedQueueIndexes).toEqual({
        type: 'array',
        items: { type: 'integer' }
      })
      expect(schema.required).toContain('resolvedQueueIndexes')
    })
  })
})
